export class QuoteDetailComponent {
  constructor(route, quoteService, authService, userService, permissionService, ngZone) {
    this.route = route;
    this.quoteService = quoteService;
    this.authService = authService;
    this.userService = userService;
    this.permissionService = permissionService;
    this.ngZone = ngZone;
    this.quote = null;
    this.loading = true;
    this.error = '';
    this.quoters = [];
    this.suppliers = [];
    this.editMode = false;
    this.quoteForm = {};
    this.uploading = false;
    this.uploadProgress = 0;
    this.assigning = false;
    this.selectedSupplierId = '';
    this.selectedFiles = [];
  }
  ngOnInit() {
    const quoteId = this.route.snapshot.paramMap.get('id');
    if (quoteId) {
      this.loadQuote(quoteId);
      if (this.authService.hasRole('admin')) {
        this.loadQuoters();
      }
      if (this.authService.hasRole('quoter') || this.authService.hasRole('admin')) {
        this.loadSuppliers();
      }
    }
  }
  loadQuote(id) {
    this.loading = true;
    this.quoteService.getQuoteById(id).subscribe({
      next: quote => {
        this.quote = quote;
        this.quoteForm = {
          ...quote
        };
        this.loading = false;
        console.log('服务器返回 supplierFile.originalName =', this.quote?.supplierFile?.originalName);
      },
      error: () => {
        this.error = '加载询价单失败';
        this.loading = false;
      }
    });
  }
  loadQuoters() {
    this.userService.getAllUsers().subscribe({
      next: users => {
        this.quoters = users.filter(user => user.role === 'quoter' && user.isActive);
      },
      error: error => {
        console.error('加载报价员失败:', error);
      }
    });
  }
  loadSuppliers() {
    this.userService.getSuppliers().subscribe({
      next: suppliers => {
        this.suppliers = suppliers;
      },
      error: error => {
        console.error('加载供应商列表失败:', error);
      }
    });
  }
  // 获取指定类型的文件列表
  getFiles(fileType) {
    if (!this.quote) return [];
    // 优先使用新的多文件字段，向后兼容旧的单文件字段
    switch (fileType) {
      case 'customer':
        return this.quote.customerFiles && this.quote.customerFiles.length > 0 ? this.quote.customerFiles : this.quote.customerFile ? [this.quote.customerFile] : [];
      case 'supplier':
        return this.quote.supplierFiles && this.quote.supplierFiles.length > 0 ? this.quote.supplierFiles : this.quote.supplierFile ? [this.quote.supplierFile] : [];
      case 'quoter':
        return this.quote.quoterFiles && this.quote.quoterFiles.length > 0 ? this.quote.quoterFiles : this.quote.quoterFile ? [this.quote.quoterFile] : [];
      default:
        return [];
    }
  }
  // 检查是否有指定类型的文件
  hasFiles(fileType) {
    return this.getFiles(fileType).length > 0;
  }
  downloadFile(fileType, fileIndex) {
    if (!this.quote || this.uploading) return;
    // 根据用户角色和询价单状态决定下载哪个文件
    const user = this.authService.getCurrentUser();
    if (!user) return;
    let actualFileType = fileType;
    if (user.role === 'customer') {
      // 客户：未报价时下载原文件，已报价时下载报价文件
